const crypto = require('crypto');

// 1. Capturar os dados de entrada
const patient = item.json.patient || {};
const newStage = item.json.new_stage;
const treatmentValue = parseFloat(item.json.treatment_value) || 0;

// 2. Normalizar e criptografar em SHA-256 (Exigência da Meta)
function sha256(text) {
  if (!text) return null;
  const cleanText = text.trim().toLowerCase();
  return crypto.createHash('sha256').update(cleanText).digest('hex');
}

function formatPhone(phone) {
  if (!phone) return null;
  // Remove tudo que não é número
  let clean = phone.replace(/\D/g, '');
  // Garante o código do país (55 para Brasil) se não houver
  if (clean.length === 11 && (clean.startsWith('1') || clean.startsWith('2') || clean.startsWith('3') || clean.startsWith('4') || clean.startsWith('5') || clean.startsWith('6') || clean.startsWith('7') || clean.startsWith('8') || clean.startsWith('9'))) {
    clean = '55' + clean;
  } else if (clean.length === 10) {
    clean = '55' + clean;
  }
  return clean;
}

const cleanPhone = formatPhone(patient.phone);
const hashedPhone = sha256(cleanPhone);
const hashedEmail = sha256(patient.email);
const hashedFirstName = sha256(patient.name ? patient.name.split(' ')[0] : null);

// 3. Mapear o nome do evento para o padrão do Facebook Ads
let eventName = 'Lead';
let value = 0;
if (newStage === 'Consulta Agendada') {
  eventName = 'Schedule';
} else if (newStage === 'Tratamento Iniciado' || newStage === 'Concluído') {
  eventName = 'Purchase';
  value = treatmentValue;
}

// 4. Montar o payload do evento
item.json.capi_payload = {
  data: [
    {
      event_name: eventName,
      event_time: Math.floor(Date.now() / 1000),
      event_source: 'physical_store',
      action_source: 'physical_store',
      user_data: {
        ph: hashedPhone ? [hashedPhone] : [],
        em: hashedEmail ? [hashedEmail] : [],
        fn: hashedFirstName ? [hashedFirstName] : []
      },
      custom_data: {
        currency: 'BRL',
        value: value
      }
    }
  ]
};

// Passar chaves necessárias do Meta Ads
item.json.meta_pixel_id = item.json.meta_pixel_id || 'SEU_PIXEL_ID';
item.json.meta_access_token = item.json.meta_access_token || 'SEU_ACCESS_TOKEN';

return item;
